(
    defaultPrim = "Shot"
    subLayers = [
        @assets.usda@
    ]
)

def Xform "Shot"
{
    def Xform "Set"
    {
        def Xform "ChairA" (
            prepend references = </Assets/Chair>
        )
        {
            double3 xformOp:translate = (-2, 0, 0)
            uniform token[] xformOpOrder = ["xformOp:translate"]
        }

        def Xform "ChairB" (
            prepend references = </Assets/Chair>
        )
        {
            double3 xformOp:translate = (2, 0, 0)
            uniform token[] xformOpOrder = ["xformOp:translate"]
        }
    }

    def Xform "Lighting" (
        variants = {
            string lightingVariant = "night"
        }
        prepend variantSets = "lightingVariant"
    )
    {
        def DistantLight "Sun"
        {
            float inputs:intensity = 50000
        }

